def _make_proc(name, pid, *, parent=None):
    """Create a mock psutil.Process with the given name, pid, and optional parent."""
    proc = MagicMock()
    proc.name.return_value = name
    proc.pid = pid
    proc.parent.return_value = parent
    return proc


def _gdbus_list_output(windows):
    """Format a window list as gdbus would return it."""
    return f"('{json.dumps(windows)}',)"


