class TestDetectContainerLinux:
    @patch("claude_dashboard.platform.linux.psutil")
    def test_detects_vscode_container(self, mock_psutil):
        systemd = _make_proc("systemd", 1)
        code_main = _make_proc("code", 6786, parent=systemd)
        code_util = _make_proc("code", 6918, parent=code_main)
        bash = _make_proc("bash", 7004, parent=code_util)
        claude = _make_proc("claude", 7492, parent=bash)
        mock_psutil.Process.return_value = claude
        mock_psutil.NoSuchProcess = psutil.NoSuchProcess
        mock_psutil.AccessDenied = psutil.AccessDenied

        result = detect_container_linux(7492)
        assert result.container_type == ContainerType.VSCODE
        assert result.process_name == "code"
        assert result.process_pid == 6918

    @patch("claude_dashboard.platform.linux.psutil")
    def test_detects_terminal_container(self, mock_psutil):
        systemd = _make_proc("systemd", 1)
